//  Buggy: Susceptible to race conditions
let currentResults = [];
async function searchBad(query) {
  // If query 1 is slow and query 2 is fast, query 1 overwrites query 2's data when it finally finishes!
  currentResults = await fetch(`/api/search?q=${query}`).then(r => r.json());
  render(currentResults);
}

//  Fixed: Using an ID to ignore outdated requests
let currentSearchId = 0;
async function searchGood(query) {
  const searchId = ++currentSearchId;
  const results = await fetch(`/api/search?q=${query}`).then(r => r.json());

  // When the fetch finishes, check if a NEWER search has started.
  // If so, throw this data away.
  if (searchId === currentSearchId) {
    currentResults = results;
    render(currentResults);
  }
}

